import React, { memo } from "react";
import { Link } from "react-router-dom";
import { motion } from "framer-motion";
import { ShieldCheck, Wrench, BatteryCharging, Sparkles, CheckCircle2, MapPin, ArrowRight } from "lucide-react";
import { Card, CardContent, CardHeader, CardTitle } from "./src/components/ui/card";

const Section = ({ id, children, className = "" }) => (
  <section id={id} className={`mx-auto w-full max-w-7xl px-6 md:px-10 ${className}`}>{children}</section>
);

const Feature = ({ icon: Icon, title, children, to }) => (
  <motion.div
    whileHover={{
      y: -12,
      scale: 1.03,
      boxShadow: '0 25px 50px rgba(0,0,0,0.25)'
    }}
    transition={{ duration: 0.4, ease: "easeOut" }}
    className="h-full"
  >
    <Card className="rounded-3xl border-white/40 bg-white/80 shadow-xl backdrop-blur dark:bg-slate-900/70 dark:border-slate-800 hover:shadow-2xl transition-all duration-300 group relative overflow-hidden h-full flex flex-col">
      <div className="absolute inset-0 bg-gradient-to-br from-[#0F62FE]/10 via-transparent to-[#0FB5AF]/10 opacity-0 group-hover:opacity-100 transition-opacity duration-500" />
      <CardHeader className="flex flex-row items-center gap-3 pb-2 relative z-10">
        <motion.div
          className="p-3 rounded-xl bg-gradient-to-br from-[#0F62FE] via-[#0FB5AF] to-[#004E92] text-white shadow-lg relative"
          whileHover={{ rotate: 10, scale: 1.15 }}
          transition={{ duration: 0.4, type: "spring", stiffness: 300 }}
        >
          <Icon className="h-6 w-6" />
          <div className="absolute inset-0 rounded-xl bg-white/30 opacity-0 group-hover:opacity-100 transition-opacity duration-300" />
        </motion.div>
        <CardTitle className="text-lg font-bold tracking-tight text-slate-900 dark:text-slate-100 group-hover:text-[#0F62FE] dark:group-hover:text-[#0FB5AF] transition-colors duration-300">{title}</CardTitle>
      </CardHeader>
      <CardContent className="text-slate-800 dark:text-slate-300 text-sm leading-relaxed relative z-10 flex-grow flex flex-col justify-between">
        <p className="mb-4">{children}</p>
        {to && (
          <motion.div
            className="flex items-center gap-2 text-[#0F62FE] dark:text-[#0FB5AF] font-semibold text-sm mt-auto cursor-pointer"
            whileHover={{ x: 5 }}
            transition={{ duration: 0.2 }}
          >
            <span>Vaata lähemalt</span>
            <motion.div
              animate={{ x: [0, 6, 0] }}
              transition={{ duration: 2, repeat: Infinity, ease: "easeInOut" }}
            >
              <ArrowRight className="h-4 w-4" />
            </motion.div>
          </motion.div>
        )}
      </CardContent>
    </Card>
  </motion.div>
);

const ServicesSection = memo(() => {
  return (
    <Section id="services" className="py-12">
      <Card className="mx-auto max-w-6xl rounded-3xl border-white/40 bg-white/80 shadow-xl backdrop-blur dark:bg-slate-900/70 dark:border-slate-800">
        <CardHeader>
          <CardTitle className="text-3xl md:text-4xl font-bold tracking-tight text-slate-900 dark:text-slate-100">
            Meie autoteenused Tallinnas
          </CardTitle>
          <div className="space-y-1 mt-2">
            <p className="text-xl md:text-2xl font-medium tracking-tight text-slate-900 dark:text-slate-100">
              Autodiagnostika Tallinnas
            </p>
            <p className="text-xl md:text-2xl font-medium tracking-tight text-slate-900 dark:text-slate-100">
              Rehvitööd ja rataste tasakaalustamine Tallinnas
            </p>
            <p className="text-xl md:text-2xl font-medium tracking-tight text-slate-900 dark:text-slate-100">
              Autopesu ja kaitsev hooldus Tallinnas
            </p>
            <p className="text-xl md:text-2xl font-medium tracking-tight text-slate-900 dark:text-slate-100">
              Mootoritööd ja elektrisüsteemide remont
            </p>
            <p className="text-xl md:text-2xl font-medium tracking-tight text-slate-900 dark:text-slate-100">
              Pidurid ja veermik — kontroll ja hooldus
            </p>
          </div>
          <p className="mt-3 max-w-2xl text-slate-800 dark:text-slate-300">
            Me ei karda keerulisi juhtumeid. Kui miski koliseb, viriseb või viskab koodi — tuleb rahulikult uurida, mitte kiirelt vahetada.
          </p>
        </CardHeader>
        <CardContent>
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
            <Link to="/piduritooed-tallinnas" className="block h-full">
              <Feature icon={ShieldCheck} title="Pidurid & veermik" to="/piduritooed-tallinnas">
                Kõik, mis teeb auto stabiilseks ja vaikseks. Kui miski koliseb või tundub vale — tule läbi, sõidame korraks koos.
              </Feature>
            </Link>
            <Link to="/mootoritooed-tallinnas" className="block h-full">
              <Feature icon={Wrench} title="Mootoritööd" to="/mootoritooed-tallinnas">
                Hooldustest kuni suuremate töödeni: rahulikult, mõõdetult, kontrollitult. Ja me selgitame, mida ning miks teeme.
              </Feature>
            </Link>
            <Link to="/elektritooed-tallinnas" className="block h-full">
              <Feature icon={BatteryCharging} title="Elekter & diagnostika" to="/elektritooed-tallinnas">
                Kui autod hakkavad «oma elu» elama — võtame süsteemi rahulikult lahti. Logime, testime ja räägime näidud läbi, mitte ei «arva» lihtsalt.
              </Feature>
            </Link>
            <Link to="/veermiku-remont-tallinnas" className="block h-full">
              <Feature icon={Sparkles} title="Detailihool & viimistlus" to="/veermiku-remont-tallinnas">
                Puhas, hoitud ja mugav — stuudio tasemel viimistlus, mis annab hea tunde iga kord, kui uksest sisse astud.
              </Feature>
            </Link>
            <motion.div
              whileHover={{ y: -8, scale: 1.02 }}
              transition={{ duration: 0.3, ease: "easeOut" }}
              className="h-full"
            >
              <Feature icon={CheckCircle2} title="Kvaliteedikontroll">
                Pärast tööd käime kõik olulised punktid läbi. Soovi korral näitame ka — kapoti all ja sellest väljaspool.
              </Feature>
            </motion.div>
            <motion.div
              whileHover={{ y: -8, scale: 1.02 }}
              transition={{ duration: 0.3, ease: "easeOut" }}
              className="h-full"
            >
              <Feature icon={MapPin} title="Ühe külastusega lahendused">
                Kui auto on juba stuudios, teeme võimalikult palju ühe korraga, et saaksid korraga korda — ei pea mitu korda tulema.
              </Feature>
            </motion.div>
          </div>
        </CardContent>
      </Card>
    </Section>
  );
});

ServicesSection.displayName = 'ServicesSection';

export default ServicesSection;
